import React, { useState } from 'react';

const IndividualAnalysis = ({ customerData, onInputChange, onAnalyze, loading, results }) => {
  const [activeTab, setActiveTab] = useState('core');

  const renderInputField = (label, field, type = 'number') => {
    return (
      <div className="input-field">
        <label className="input-label">{label}</label>
        <input
          type={type}
          value={customerData[field]}
          onChange={(e) => onInputChange(field, type === 'number' ? parseFloat(e.target.value) || 0 : e.target.value)}
          className="input-control"
          step={type === 'number' ? 'any' : undefined}
        />
      </div>
    );
  };

  return (
    <div className="individual-analysis">
      <div className="analysis-header">
        <h2>👤 Customer Profile Data Input</h2>
      </div>
      {/* Tabs */}
      <div className="analysis-tabs">
        <div className="tabs-navigation">
          <button
            className={`tab-button ${activeTab === 'core' ? 'active' : ''}`}
            onClick={() => setActiveTab('core')}
          >
            💰 Core Metrics
          </button>
          <button
            className={`tab-button ${activeTab === 'service' ? 'active' : ''}`}
            onClick={() => setActiveTab('service')}
          >
            🛠️ Service & Logistics
          </button>
          <button
            className={`tab-button ${activeTab === 'demographic' ? 'active' : ''}`}
            onClick={() => setActiveTab('demographic')}
          >
            🧑‍ Demographic Data
          </button>
        </div>
        <div className="tab-content">
          {activeTab === 'core' && (
            <div className="input-grid">
              <div className="input-column">
                {renderInputField("1. Customer Lifetime (Months)", "Tenure")}
                {renderInputField("2. Total Orders", "OrderCount")}
                {renderInputField("3. Total Cashback Earned (₹)", "CashbackAmount")}
                {renderInputField("4. Days Since Last Order", "DaySinceLastOrder")}
              </div>
              <div className="input-column">
                {renderInputField("5. App Time (Hours/month)", "HourSpendOnApp")}
                {renderInputField("6. Perceived Price Increase (%)", "OrderAmountHikeFromlastYear")}
                {renderInputField("7. Coupons Used", "CouponUsed")}
                {renderInputField("8. Devices Registered", "NumberOfDeviceRegistered")}
              </div>
            </div>
          )}
          {activeTab === 'service' && (
            <div className="input-grid">
              <div className="input-column">
                {renderInputField("9. Satisfaction Score (1-5)", "SatisfactionScore")}
                {renderInputField("10. Warehouse Distance (km)", "WarehouseToHome")}
                {renderInputField("11. Delivery Addresses", "NumberOfAddress")}
                {renderInputField("12. City Tier", "CityTier")}
              </div>
              <div className="input-column">
                <div className="input-field">
                  <label className="input-label">13. Login Device</label>
                  <select
                    value={customerData.PreferredLoginDevice}
                    onChange={(e) => onInputChange("PreferredLoginDevice", e.target.value)}
                    className="input-control"
                  >
                    <option value="Mobile Phone">Mobile Phone</option>
                    <option value="Computer">Computer</option>
                  </select>
                </div>
                <div className="input-field">
                  <label className="input-label">14. Payment Mode</label>
                  <select
                    value={customerData.PreferredPaymentMode}
                    onChange={(e) => onInputChange("PreferredPaymentMode", e.target.value)}
                    className="input-control"
                  >
                    <option value="Credit Card">Credit Card</option>
                    <option value="Debit Card">Debit Card</option>
                    <option value="UPI">UPI</option>
                    <option value="E wallet">E wallet</option>
                    <option value="Cash on Delivery">Cash on Delivery</option>
                  </select>
                </div>
                <div className="input-field">
                  <label className="input-label">15. Order Category</label>
                  <select
                    value={customerData.PreferedOrderCat}
                    onChange={(e) => onInputChange("PreferedOrderCat", e.target.value)}
                    className="input-control"
                  >
                    <option value="Laptop & Accessory">Laptop & Accessory</option>
                    <option value="Mobile Phone">Mobile Phone</option>
                    <option value="Fashion">Fashion</option>
                    <option value="Grocery">Grocery</option>
                    <option value="Books & Stationery">Books & Stationery</option>
                    <option value="Footwear">Footwear</option>
                    <option value="Sports Equipment">Sports Equipment</option>
                    <option value="Others">Others</option>
                  </select>
                </div>
              </div>
            </div>
          )}
          {activeTab === 'demographic' && (
            <div className="input-grid">
              <div className="input-column">
                <div className="input-field">
                  <label className="input-label">16. Gender</label>
                  <select
                    value={customerData.Gender}
                    onChange={(e) => onInputChange("Gender", e.target.value)}
                    className="input-control"
                  >
                    <option value="Male">Male</option>
                    <option value="Female">Female</option>
                    <option value="Other">Other</option>
                  </select>
                </div>
                <div className="input-field">
                  <label className="input-label">17. Marital Status</label>
                  <select
                    value={customerData.MaritalStatus}
                    onChange={(e) => onInputChange("MaritalStatus", e.target.value)}
                    className="input-control"
                  >
                    <option value="Married">Married</option>
                    <option value="Single">Single</option>
                    <option value="Divorced">Divorced</option>
                    <option value="Other">Other</option>
                  </select>
                </div>
              </div>
              <div className="input-column">
                <div className="input-field">
                  <label className="input-label">18. Has Formal Complaint?</label>
                  <div className="toggle-group">
                    <button
                      className={`toggle-btn ${customerData.Complain ? 'active' : ''}`}
                      onClick={() => onInputChange("Complain", 1)}
                    >
                      Yes
                    </button>
                    <button
                      className={`toggle-btn ${!customerData.Complain ? 'active' : ''}`}
                      onClick={() => onInputChange("Complain", 0)}
                    >
                      No
                    </button>
                  </div>
                </div>
              </div>
            </div>
          )}
        </div>
      </div>
      <button
        className="analyze-button primary"
        onClick={onAnalyze}
        disabled={loading}
      >
        {loading ? '🔄 Analyzing...' : '✨ Analyze Customer Risk Now'}
      </button>
      {/* Results Display */}
      {results && (
        <div className="results-section">
          <h3>Analysis Results</h3>
          <div className="risk-indicator">
            <div className={`risk-badge ${results.risk_level.toLowerCase()}`}>
              {results.risk_level} RISK ({(results.probability * 100).toFixed(1)}%)
            </div>
            <p>Primary risk factor: <strong>{results.top_driver}</strong></p>
          </div>
        </div>
      )}
    </div>
  );
};

export default IndividualAnalysis;
